-                               : APInt::getHighBitsSet(BitWidth, Num + 1);
-      APInt Mask2 = IsTrailing
-        ? APInt::getOneBitSet(BitWidth, Num)
-        : APInt::getOneBitSet(BitWidth, BitWidth - Num - 1);
-      return new ICmpInst(Pred, Builder.CreateAnd(II->getArgOperand(0), Mask1),
