-  if (!Combination)
-    return nullptr;
-
-  CmpInst::Predicate EquivPred;
-  APInt EquivInt;
-  APInt EquivOffset;
-
-  Combination->getEquivalentICmp(EquivPred, EquivInt, EquivOffset);
-
-  return new ICmpInst(
-      EquivPred,
-      Builder.CreateAdd(Op0, ConstantInt::get(Op1->getType(), EquivOffset)),
-      ConstantInt::get(Op1->getType(), EquivInt));
-}
