-static Instruction *foldCtpopPow2Test(ICmpInst &I, IntrinsicInst *CtpopLhs,
-                                      const APInt &CRhs,
-                                      InstCombiner::BuilderTy &Builder,
-                                      const SimplifyQuery &Q) {
