-  case ICmpInst::Predicate::ICMP_ULT:
-    //  x & Mask u< x
-    //    -> x u> Mask
-    //  x & ~Mask u< ~Mask
-    //    -> ~Mask u> x
-    DstPred = ICmpInst::Predicate::ICMP_UGT;
-    break;
-  case ICmpInst::Predicate::ICMP_UGE:
-    //  x & Mask u>= x
-    //    -> x u<= Mask
-    //  x & ~Mask u>= ~Mask
-    //    -> ~Mask u<= x
