-    return nullptr;
-
-  // Power of 2 test:
-  //    isPow2OrZero : ctpop(X) u< 2
-  //    isPow2       : ctpop(X) == 1
-  //    NotPow2OrZero: ctpop(X) u> 1
-  //    NotPow2      : ctpop(X) != 1
-  // If we know any bit of X can be folded to:
-  //    IsPow2       : X & (~Bit) == 0
-  //    NotPow2      : X & (~Bit) != 0
-  const ICmpInst::Predicate Pred = I.getPredicate();
