-          (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_ULT)
-              ? ICmpInst::ICMP_EQ
-              : ICmpInst::ICMP_NE,
-          And, Constant::getNullValue(Op->getType()));
-    }
-  }
